// ------------------- Картинки -------------------
export const ScaleImg = ({ className, src, alt='IMG' }) => (
  <motion.img
    src={src} className={className} alt={alt}
    initial={{ scale: 0 }} animate={{ scale: 1 }}
    transition={{ duration: 0.4, scale: { type: "spring", visualDuration: 0.6, bounce: 0.9 } }}
  />
);

export const ImgPulse = ({ className, src, alt='icon' }) => (
  <motion.img
    src={src} className={className} alt={alt}
    initial={{ opacity: 0 }} animate={{ opacity: [0.6, 1, 0.6] }}
    transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
    whileHover={{ opacity: 1 }}
  />
);

export const HoverScale = ({ src, alt, className }) => (
  <motion.img src={src} alt={alt} className={className} whileHover={{ scale: 1.1 }} transition={{ duration: 0.2 }} />
);

// ------------------- Текст -------------------
export const AnimatedText = ({ children,className="" }) => {
  const { i18n } = useTranslation();
  return (
    <AnimatePresence  mode="wait">
      <motion.span
        className={className}
        key={i18n.language}
        style={{ display: "inline-block" }}
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -8 }}
        transition={{ duration: 0.25 }}
      >
        {children}
      </motion.span>
    </AnimatePresence>
  );
};

// ------------------- Карточки -------------------
export const MotionCard = ({ children, className }) => (
  <motion.div className={className} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.3 }} whileHover={{ scale: 1.05 }}>
    {children}
  </motion.div>
);

// ------------------- PortfolioCards -------------------

// Компонент для отдельной карточки с parallax
const PortfolioCardItem = ({
  card,
  index
}) => {
const { t } = useTranslation();
  return (
    <motion.div
      whileHover={{ scale: 1.01 }}
      className="portfolioCard"
      data-label={t(card.labelKey)}
      transition={{
        type: "spring",
        stiffness: 200,
        damping: 20
      }}
    >
      <img src={card.image} alt={t(card.titleKey)} className="cardImage" />

      <AnimatedText className="cardTitle">
        <h3>{t(card.titleKey)}</h3>
        <p>{t(card.descKey)}</p>
      </AnimatedText>
    </motion.div>
  );
};

export const PortfolioCards = () => {
  return (
    <div className="portfolioContainer">
      {HomeCards.map((card, index) => (
        <PortfolioCardItem
          key={index}
          card={card}
          index={index}
        />
      ))}
    </div>
  );
};


export const FooterIcons = ({ className, src }) => {
  return (
    <motion.img className={className} src={src} initial={{ y: -50 }} animate={{ y: 0 }} transition={{ duration: 1, delay: 0.2 }} />
  )
}

export const Loader = () => {
  const [load, setLoad] = useState(true)
  useEffect(()=>{
    const timer = setTimeout(() => {
      setLoad(false)
    }, 2000);
    return () => clearTimeout(timer);
  }, [])

  return(
    <AnimatePresence>
      {load && (
        <motion.div
          className="loader"
          initial={{ y: 0 }}
          exit={{ y: "-100vh" }}
          transition={{ duration: 1.6, ease: "easeInOut" }}
        >
          <motion.img src={JS} alt={'IMG'}
          initial={{
            y:-150,
            x:-200
          }}
          animate={{
            scale: 1,
            y:0,
            x:0
          }}
          transition={{
            duration: 1.6,
            ease: [0.77, 0, 0.175, 1],
            delay: .1,
          }}/>
        <motion.img src={Python} alt={'IMG'}
          initial={{
            y:150,
            x:-200
          }}
          animate={{
            scale: 1,
            y:0,
            x:0
          }}
          transition={{
            duration: 1.6,
            ease: [0.77, 0, 0.175, 1],
            delay: .1,
          }}/>
          <motion.img src={coffee} alt={'IMG'} 
          initial={{
            y:-150,
            x:200
          }}
          animate={{
            y:0,
            x:0
          }}
          transition={{
            duration: 1.6,
            ease: [0.77, 0, 0.175, 1],
            delay: .1,
          }}/>
          <motion.img src={brain} alt={'IMG'} 
          initial={{
            y:150,
            x:200
          }}
          animate={{
            scale: 1,
            y:0,
            x:0
          }}
          transition={{
            duration: 1.6,
            ease: [0.77, 0, 0.175, 1],
            delay: .1,
          }}/>
          <motion.img  src={Suitcase} 
          animate={{
            scale: 1.5
          }} 
          transition={{
            duration: 1.6,
            // ease: [0.77, 0, 0.175, 1],
            delay: .1,
          }}/>
        </motion.div>

      )}
    </AnimatePresence>
  )
}