

import './../styles/style.scss'
import logo from './../assets/Frame2.svg'
import { MotionDivNavbar, LinkNav, ScaleImg, AnimatedText} from './motions.jsx'
import { useTranslation } from "react-i18next";
import {useState, useEffect} from 'react'
import { NavLink } from "react-router-dom";
import {ProgressLine} from './progressLine.jsx'

function Header(){
    const { i18n } = useTranslation();
    const { t } = useTranslation();
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [isMobile, setIsMobile] = useState(window.innerWidth < 475);

    useEffect(() => {
        const handleResize = () => {
            setIsMobile(window.innerWidth < 475);
            if (window.innerWidth >= 475) {
                setIsMobileMenuOpen(false);
            }
        };

        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const toggleLanguage = () => {
        const newLang = i18n.language === "en" ? "ru" : "en";
        i18n.changeLanguage(newLang);
        localStorage.setItem("lang", newLang);
    };

    const [active, setActive] = useState(false);
    const handleClick = () => {
        toggleLanguage();
        setActive(prev => !prev);
    };

    const toggleMobileMenu = () => {
        setIsMobileMenuOpen(!isMobileMenuOpen);
    };


    return(
        <div>
            <header>
             <nav className="navbar">
                    <ScaleImg src={logo} className='logo'/>

                        {!isMobile && (
                        <MotionDivNavbar className='navLinks'>
                            <AnimatedText><LinkNav to='/'>{t("home.home")}</LinkNav></AnimatedText>
                            <AnimatedText><LinkNav to='/projects'>{t("home.projects")}</LinkNav></AnimatedText>
                            
                            <AnimatedText><button className={active ? "ruBtn" : 'enBtn' } onClick={handleClick}>
                                {i18n.language === "en" ? "RU" : "EN"}
                            </button></AnimatedText>
                        </MotionDivNavbar>
                        )}

                        {isMobile && (
                            <div className="mobile-nav">
                                <button className="burger-menu" onClick={toggleMobileMenu} aria-label="Toggle menu">
                                    <span className={`burger-line ${isMobileMenuOpen ? 'open' : ''}`}></span>
                                    <span className={`burger-line ${isMobileMenuOpen ? 'open' : ''}`}></span>
                                    <span className={`burger-line ${isMobileMenuOpen ? 'open' : ''}`}></span>
                                </button>
                                <button className={active ? "ruBtn" : 'enBtn' } onClick={handleClick}>
                                    {i18n.language === "en" ? "RU" : "EN"}
                                </button>
                            </div>
                        )}
             </nav>
             {isMobile && isMobileMenuOpen && (
                <nav className="nav">
                  <NavLink
                    to="/"
                    className={({ isActive }) =>
                      isActive ? "link active top" : "link"
                    }
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    {t("home.home")}
                  </NavLink>

                  <NavLink
                    to="/projects"
                    className={({ isActive }) =>
                      isActive ? "link active bottom" : "link"
                    }
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    {t("home.projects")}
                  </NavLink>
                </nav>
             )}
             <ProgressLine></ProgressLine>
            </header>
        </div>
    )
}




export default Header;